+        let t3 = Utc.with_ymd_and_hms(2026, 1, 1, 0, 0, 2).unwrap();
+
+        ctrl.record_update("op1", make_update("a", 10, Some(100)), t1);
+        ctrl.record_phase_transition("op1", "b", &[], t2);
